solutions.javascript:
// Solution
function validateUserId(req, res, next) {
  const id = parseInt(req.params.id);
  if (isNaN(id) || id <= 0) {
    res.status(400).json({ status: 400, message: 'User ID is not a positive integer' });
  } else {
    next();
  }
}

// Example usage:
app.use('/users/:id', validateUserId, function(req, res) {
  // Handle the request
  res.json({ status: 200, message: 'User ID is valid' });
});
